# TDAbleton Integration
# Assumes TDAbleton M4L device is running in Ableton
# and the TDAbleton component is loaded in TD

# Standard TDAbleton port config:
# Ableton sends OSC to TD on port 7000
# TD sends OSC to Ableton on port 9000

class TDAbletonBridge:
    def __init__(self, oscInDat, oscOutDat):
        self.osc_in = oscInDat
        self.osc_out = oscOutDat
        self.tempo = 120.0
        self.beat = 0
        self.playing = False
        self.clips = {}  # track -> {clip_index -> clip_info}

    def on_receive_osc(self, address, args):
        """
        Handle messages from Ableton via TDAbleton.
        Called by OSC In DAT callback.
        """
        if address == '/live/song/get/tempo':
            self.tempo = float(args[0])
            op('bpm_display').par.value0 = self.tempo

        elif address == '/live/song/get/is_playing':
            self.playing = bool(args[0])

        elif address == '/live/song/get/current_song_time':
            beat_time = float(args[0])
            self.beat = int(beat_time) % 4

        elif address.startswith('/live/clip/get/'):
            # Handle clip state updates
            parts = address.split('/')
            # e.g. /live/clip/get/playing_status
            pass

    # --- Control Ableton from TD ---
    def play(self):
        self.osc_out.sendOSC('/live/song/start_playing', [])

    def stop(self):
        self.osc_out.sendOSC('/live/song/stop_playing', [])

    def set_tempo(self, bpm):
        self.osc_out.sendOSC('/live/song/set/tempo', [float(bpm)])

    def trigger_clip(self, track, clip):
        self.osc_out.sendOSC('/live/clip_slot/fire', [int(track), int(clip)])

    def stop_clip(self, track):
        self.osc_out.sendOSC('/live/track/stop_all_clips', [int(track)])

    def set_track_volume(self, track, volume):
        """volume: 0.0..1.0"""
        self.osc_out.sendOSC('/live/track/set/volume', [int(track), float(volume)])

    def set_device_param(self, track, device, param, value):
        """Control any Ableton device parameter."""
        self.osc_out.sendOSC('/live/device/set/parameter/value',
                             [int(track), int(device), int(param), float(value)])

# Ableton Link CHOP — hardware-synced tempo
# No setup needed beyond adding the Ableton Link CHOP
# It auto-discovers Link sessions on the network
def get_link_tempo(abletonLinkChop):
    """Read current Ableton Link tempo."""
    if 'tempo' in [c.name for c in abletonLinkChop.chans()]:
        return abletonLinkChop['tempo'][0]
    return 120.0

def get_link_beat(abletonLinkChop):
    """Read current beat position from Ableton Link."""
    if 'beat' in [c.name for c in abletonLinkChop.chans()]:
        return abletonLinkChop['beat'][0]
    return 0.0
